import React from "react";
import { useParams, Link } from "react-router-dom";
import "./BookingConfirmation.css";

const listings = [
  { id: 1, name: "Luxury Beach Villa", price: "$250/night", image: "https://images.pexels.com/photos/2102587/pexels-photo-2102587.jpeg" },
  { id: 2, name: "Cozy Mountain Cabin", price: "$180/night", image: "https://images.pexels.com/photos/277572/pexels-photo-277572.jpeg" },
  { id: 3, name: "Modern City Apartment", price: "$200/night", image: "https://images.pexels.com/photos/271624/pexels-photo-271624.jpeg" },
  { id: 4, name: "Traditional Heritage Home", price: "$220/night", image: "https://images.pexels.com/photos/259588/pexels-photo-259588.jpeg" },
];

const experiences = [
  { id: 101, name: "Skydiving Adventure", price: "$150/person", image: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=800&q=80" },
  { id: 102, name: "Mountain Hiking", price: "$90/person", image: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=800&q=80" },
  { id: 103, name: "Scuba Diving", price: "$200/person", image: "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=800&q=80" },
  { id: 104, name: "Desert Safari", price: "$120/person", image: "https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?fit=crop&w=800&q=80" },
  { id: 105, name: "Camping Under Stars", price: "$100/person", image: "https://images.unsplash.com/photo-1506744038136-46273834b3fb?fit=crop&w=800&q=80" },
];

const services = [
  { id: 201, name: "Hotel Booking", price: "$300", image: "https://images.unsplash.com/photo-1568605114967-8130f3a36994?fit=crop&w=800" },
  { id: 202, name: "Makeup & Salon", price: "$80", image: "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=800" },
  { id: 203, name: "Car Rentals", price: "$100/day", image: "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=800" },
  { id: 204, name: "Tour Guides", price: "$60/hour", image: "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?fit=crop&w=800" },
];

export default function BookingConfirmation() {
  const { id } = useParams();
  const bookingId = Number(id);

  const booking =
    listings.find((item) => item.id === bookingId) ||
    experiences.find((item) => item.id === bookingId) ||
    services.find((item) => item.id === bookingId);

  if (!booking) {
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>Booking not found.</h2>;
  }

  return (
    <div className="booking-page">
      <h1>🎉 Booking Confirmed</h1>
      <div className="booking-card">
        <img src={booking.image} alt={booking.name} />
        <h2>{booking.name}</h2>
        <p className="price">Total: <strong>{booking.price}</strong></p>
        <p>Your booking has been successfully confirmed! 🏡</p>

        <h3>💳 Choose a Payment Method</h3>
        <div className="payment-options">
          <label><input type="radio" name="payment" /> UPI (Google Pay, PhonePe, Paytm)</label>
          <label><input type="radio" name="payment" /> Credit / Debit Card</label>
          <label><input type="radio" name="payment" /> Pay on Arrival (Cash / Card)</label>
        </div>

        <button className="confirm-btn">Confirm Payment</button>

        <Link to="/">
          <button className="back-home-btn">⬅ Back to Home</button>
        </Link>
      </div>
    </div>
  );
}
